#include<bits/stdc++.h>
using namespace std;
long long v[10025],p[10025],dp[100025];
int main() {
	int n,m;
	cin>>n>>m;
	for(int i=1; i<=m; i++) cin>>v[i]>>p[i];
	for(int i=1; i<=m; i++) {
		for(int j=n; j>=v[i]; j--) {
			dp[j]=max(dp[j],dp[j-v[i]]+v[i]*p[i]);

		}
	}
	cout<<dp[n]<<endl;
	return 0;
}
